# ---------------------------------------------------------------------------
# tower.map  -  a small second level so the menu shows more than one choice.
# Build your own in level_editor (Save writes back here / to a new .map).
# ---------------------------------------------------------------------------

spawn 0 1.2 7 0
ambient 0.14
floor floor
ceiling 4 ceiling

light point 0 3.6 0 1.0 0.92 0.82 2.4 0.008
light dir 0.3 -1 -0.2 0.30 0.35 0.5 0.45

# Outer walls (smaller arena, [-7,7]).
wall -7.4 0 -7.4  -7.0 4 7.4  panel
wall  7.0 0 -7.4   7.4 4 7.4  panel
wall -7.4 0 -7.4   7.4 4 -7.0 panel
wall -7.4 0  7.0   7.4 4 7.4  panel

# Central tower of stacked boxes (cover + verticality).
box 0 0.5 0 2.0 metal
box 0 1.5 0 1.6 brick
box 0 2.4 0 1.2 metal

# Corner orbs.
prop orb -5 1.2 -5
prop orb  5 1.2 -5
prop orb -5 1.2  5
prop orb  5 1.2  5

weapon pistol 0 0.6 4

# A faster, tankier mix of enemies.
enemy brute  0 1.2 -5
enemy grunt -3 1 -3
enemy grunt  3 1 -3
enemy sniper -6 1 0
enemy sniper  6 1 0
